import React, { useState, useEffect } from 'react';
import EmployeeList from './components/EmployeeList';
import EmployeeForm from './components/EmployeeForm';
import SearchBar from './components/SearchBar';
import { employeeService } from './services/employeeService';
import './App.css';

/**
 * Main application component
 * Manages the employee directory application state and layout
 */
function App() {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState(null);

  /**
   * Fetch employees from the API
   * @param {string} search - Optional search term
   */
  const fetchEmployees = async (search = '') => {
    try {
      setLoading(true);
      setError('');
      const response = await employeeService.getAllEmployees(search);
      setEmployees(response.data || []);
    } catch (err) {
      setError('Failed to fetch employees. Please try again.');
      console.error('Error fetching employees:', err);
    } finally {
      setLoading(false);
    }
  };

  // Load employees on component mount and when search term changes
  useEffect(() => {
    fetchEmployees(searchTerm);
  }, [searchTerm]);

  /**
   * Handle search input change
   * @param {string} term - Search term
   */
  const handleSearch = (term) => {
    setSearchTerm(term);
  };

  /**
   * Handle adding a new employee
   * @param {Object} employeeData - New employee data
   */
  const handleAddEmployee = async (employeeData) => {
    try {
      await employeeService.createEmployee(employeeData);
      setShowForm(false);
      fetchEmployees(searchTerm); // Refresh the list
    } catch (err) {
      setError('Failed to add employee. Please try again.');
      console.error('Error adding employee:', err);
    }
  };

  /**
   * Handle updating an existing employee
   * @param {Object} employeeData - Updated employee data
   */
  const handleUpdateEmployee = async (employeeData) => {
    try {
      await employeeService.updateEmployee(editingEmployee._id, employeeData);
      setShowForm(false);
      setEditingEmployee(null);
      fetchEmployees(searchTerm); // Refresh the list
    } catch (err) {
      setError('Failed to update employee. Please try again.');
      console.error('Error updating employee:', err);
    }
  };

  /**
   * Handle editing an employee
   * @param {Object} employee - Employee to edit
   */
  const handleEditEmployee = (employee) => {
    setEditingEmployee(employee);
    setShowForm(true);
  };

  /**
   * Handle deleting an employee
   * @param {string} id - Employee ID to delete
   */
  const handleDeleteEmployee = async (id) => {
    if (window.confirm('Are you sure you want to delete this employee?')) {
      try {
        await employeeService.deleteEmployee(id);
        fetchEmployees(searchTerm); // Refresh the list
      } catch (err) {
        setError('Failed to delete employee. Please try again.');
        console.error('Error deleting employee:', err);
      }
    }
  };

  /**
   * Close the form and reset editing state
   */
  const handleCloseForm = () => {
    setShowForm(false);
    setEditingEmployee(null);
  };

  return (
    <div className="app">
      <header className="app-header">
        <h1>Employee Directory</h1>
        <p>Manage and search your employee database</p>
      </header>

      <main className="app-main">
        <div className="app-controls">
          <SearchBar onSearch={handleSearch} />
          <button 
            className="btn btn-primary"
            onClick={() => setShowForm(true)}
          >
            Add Employee
          </button>
        </div>

        {error && (
          <div className="error-message">
            {error}
          </div>
        )}

        {loading ? (
          <div className="loading">Loading employees...</div>
        ) : (
          <EmployeeList
            employees={employees}
            onEdit={handleEditEmployee}
            onDelete={handleDeleteEmployee}
          />
        )}

        {showForm && (
          <EmployeeForm
            employee={editingEmployee}
            onSubmit={editingEmployee ? handleUpdateEmployee : handleAddEmployee}
            onCancel={handleCloseForm}
          />
        )}
      </main>
    </div>
  );
}

export default App;
